// Script Continued Below

// This file should always remain Active = false
// This file will be read only so customers don't use it, but create thier own version in the Tasker app to avoid us overwriting on a future release
// This file:
// - Provides an example of what should go in the customer's script include to customize an existing ACL on a field
// - Provides an example of the code that would chagne in an existing ACL (from and to)
// - Provides an example of what should go in the customer's script include to create a function for a customer's custom field
// - Provides an example of what should go in the customer's ACL for a customer's custom field

// Here is the list of fields available from the global taskPermission object that can be used to in setting permissions
// - g_taskPermissions.number - used to keep track of the row being processed
// - g_taskPermissions.isTaskManagerOUTA - true if the current user the task manager of the Primary Assignee OU
// - g_taskPermissions.reviewerInOUTA_OU = true if the reviewer is in the Primary Assignee OU
// - g_taskPermissions.isTAExternal - true if the Tasking Authority is External
// - g_taskPermissions.isExternalOutbound - true if the task an external outbound task
// - g_taskPermissions.isExternal - true if the Tasking Authority of the Task is external or the task is an external outboud task
// - g_taskPermissions.isSubTask - true if the task is a subtask
// - g_taskPermissions.isReviewRequired - true if task must be reviwed
// - g_taskPermissions.state - this is the numerical value of the state of the task;
//         States are: 'New', Unassigned {-5}, Waiting {-3}, Assigned {1}, Accepted {10}, Work in Progress {13}, In Review {14},
//                     Rework {15}, 'RejectedAssignment', 'RejectedPrimaryAssignee', 
//                     Completed {3}, Completed Incomplete {4},Cancelled {7} 
// - g_taskPermissions.isTaskerApplicationAdmin - true if the user is an tasker application administrator 
// - g_taskPermissions.isTaskAdministratorGTA - true if the user is a Task Administrator
// - g_taskPermissions.isTaskExecutive = true if the user is a Task Executive
// - g_taskPermissions.isUserOUTAOfAnotherUserBasedOnDefaultOu - true if the taskOwner is the task manager of the default ou of the user
// - g_taskPermissions.isTaskerUser - true if user has the task user role
// - g_taskPermissions.isParentTaskOwner - true if the user is the task owner of the parent task
// - g_taskPermissions.isParentTaskAssignedMember - true if hte current user is the assigned the parent task
// - g_taskPermissions.isUserInPrimaryAssigneeOU - true if the user is in the Primary Assignee OU
// - g_taskPermissions.isOnBehalfOf - true if the current user is the on_behalf_of user of the task
// - g_taskPermissions.isReviewer - true if the current user is the Reviewer of the current task
// - g_taskPermissions.isTaskOwner - true if the current user is the Task Owner of the task
// - g_taskPermissions.isAssignedMember - true if the current user is the Assigned Member of the task
// - g_taskPermissions.primaryOUMustMatchInternalTAOU - true if the global setting for Primary OU must match Tasking Authority is true
// - g_taskPermissions.isReviewType - true if the task is a Review Task Type
// - g_taskPermissions.isStandardType - true if the task is a Standard Task Type

var example_ACL_Customization = Class.create();
example_ACL_Customization.prototype = {
    initialize: function(grTask) {
		// in the initilization call TaskACLs, this will force the g_taskPermissions object to be in sync with the task for this field
		var TaskACLs = new TaskerTaskACLs(grTask);
    },



	// *******************************************************************************************************************************
	// Example 1 - Change an existing field to add permissions 
	// *******************************************************************************************************************************
	// ****** 2 code blocks below
	// *******************************************************************************************************************************
	// ****** 1st code block shows how to change the ACL to call the custom script include to use custom script instead of OOTB script
	// *******************************************************************************************************************************
	// ****** 2nd code block shows the code to put in the custom script include to change the field to add more permissions for users
	// *******************************************************************************************************************************
	// Example 1 - 1st code block - ACL Update
	// *******************************************************************************************************************************
	// here is the code in the ACL for x_153465_discovert_route_task_instance.on_behalf_of
	// OLD Code
	// var TaskACLs = new TaskerTaskACLs(current);
	// answer = TaskACLs.setOnBehalfOfPermissions();
	// NEW Code
	// var example_ACL_Customization = new example_ACL_Customization(current);
	// answer = example_ACL_Customization.custom_setOnBehalfOfPermissions();
	// *******************************************************************************************************************************
	// Example 1 - 2nd code block - what to copy out of the TaskerTaskACL file and what to chanage
	// *******************************************************************************************************************************
	// This is the example for changing a field
	// The example adds Task Manager and Task Administrator to the people who can change the onBehalfOf field
	// the code comment out is the way it was
	// the code not commetted is the updated code to add the 2 additioinal users
	custom_setOnBehalfOfPermissions: function(){
		var answer = false;
		// example of code in TaskerTaskACLs
		//switch(g_taskPermissions.state){
		//	case 'New': 
		//		answer = true;
		//		break;
		//	// Unassigned {-5}, Waiting {-3}, Assigned {1}, Accepted {10}, Work in Progress {13}, In Review {14}, Rework {15}
		//	case -5: case -3: case 1: case 10: case 13: case 14: case 15: case 'RejectedAssignment': case 'RejectedPrimaryAssignee':
		//		answer = (g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner);
		//		break;
		//		
		//	// Completed {3}, Completed Incomplete {4},Cancelled {7} 
		//	case 3: case 4: case 7:
		//		answer = false;
		//		break;
		//	default:
		//		answer = false;
		//		break;
		//}
		// The code below shows how to add permissiosn to allow Task Administrator and the Task Manager of the Primary Assigneee to change the onbehalf of user for all states not completed
		switch(g_taskPermissions.state){
			case 'New': 
				answer = true;
				break;
			// Unassigned {-5}, Waiting {-3}, Assigned {1}, Accepted {10}, Work in Progress {13}, In Review {14}, Rework {15}
			case -5: case -3: case 1: case 10: case 13: case 14: case 15: case 'RejectedAssignment': case 'RejectedPrimaryAssignee':
				// added (********************************************************************************)
				// STRY0112587
				answer = (g_taskPermissions.isTaskAdministratorGTA || g_taskPermissions.isTaskExecutive || g_taskPermissions.isTaskManagerOUTA || g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner);
				break;

			// Completed {3}, Completed Incomplete {4},Cancelled {7} 
			case 3: case 4: case 7:
				answer = false;
				break;
			default:
				answer = false;
				break;
		}		
		return answer;
	},
	// *******************************************************************************************************************************
	// Example 1 - END
	// *******************************************************************************************************************************

	// *******************************************************************************************************************************
	// Example 2 - Add a customer's custom field permissions 
	// *******************************************************************************************************************************
	// ****** 2 code blocks below
	// *******************************************************************************************************************************
	// ****** 1st code block shows what to pout int he ACL for the customer's custom field
	// *******************************************************************************************************************************
	// ****** 2nd code block shows the code to add to the custom script include to add the permissions for the new field
	// *******************************************************************************************************************************
	// Example 2 - 1st code block - ACL Add
	// *******************************************************************************************************************************
	// here is the code in the ACL for x_153465_discovert_route_task_instance.u_custom_field
	// NEW Code
	// var example_ACL_Customization = new example_ACL_Customization(current);
	// answer = example_ACL_Customization.set_u_custom_field();
	// *******************************************************************************************************************************
	// Example 2 - 2nd code block - what to add to the custom Task ACL script include for a new field
	// *******************************************************************************************************************************
	// This is the example for adding a new field
	// The example has the new field mimic the permissiosn form Example 1 above
	set_u_custom_field: function(){
		var answer = false;
		// The code below shows how to add permissiosn to allow Task Administrator and the Task Manager of the Primary Assigneee to change the onbehalf of user for all states not completed
		switch(g_taskPermissions.state){
			case 'New': 
				answer = true;
				break;
			// Unassigned {-5}, Waiting {-3}, Assigned {1}, Accepted {10}, Work in Progress {13}, In Review {14}, Rework {15}
			case -5: case -3: case 1: case 10: case 13: case 14: case 15: case 'RejectedAssignment': case 'RejectedPrimaryAssignee':

				// STRY0112587
				answer = (g_taskPermissions.isTaskAdministratorGTA || g_taskPermissions.isTaskExecutive || g_taskPermissions.isTaskManagerOUTA || g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner);
				break;

			// Completed {3}, Completed Incomplete {4},Cancelled {7} 
			case 3: case 4: case 7:
				answer = false;
				break;
			default:
				answer = false;
				break;
		}		
		return answer;
	},
	// *******************************************************************************************************************************
	// Example 2 - END
	// *******************************************************************************************************************************	

	type: 'example_ACL_Customization'
};
